const ctx = $input.first().json;
const task = ctx.task || {};
const nexus = ctx.nexusContext || {};
const deptAnalysis = ctx.departmentAnalysis || '';
const webSources = (ctx.webSources || []).slice(0, 15);
const docs = ctx.generatedDocs || [];

// Build comprehensive development prompt
let prompt = `# משימת פיתוח: ${task.title}\n\n`;
prompt += `## תיאור המשימה\n${task.description || 'אין תיאור'}\n\n`;

if (nexus.sourceDepartment) {
  prompt += `## מחלקה מקורית: ${nexus.sourceDepartment}\n\n`;
}

if (deptAnalysis) {
  prompt += `## ניתוח מחלקה מלא\n${deptAnalysis.slice(0, 3000)}\n\n`;
}

if (webSources.length > 0) {
  prompt += `## מקורות מחקר (${webSources.length})\n`;
  for (const s of webSources) {
    prompt += `- [${s.source_type}] ${s.title} (trust: ${s.trust_score}) ${s.url}\n`;
    if (s.snippet) prompt += `  ${s.snippet.slice(0, 150)}\n`;
  }
  prompt += '\n';
}

if (docs.length > 0) {
  prompt += `## מסמכי מפרט\n`;
  for (const d of docs) {
    prompt += `### ${d.title} (${d.docType})\n${(d.content || '').slice(0, 2000)}\n\n`;
  }
}

prompt += `\n---\n## הנחיות לפיתוח\n`;
prompt += `1. קרא את כל ההקשר למעלה לפני שאתה מתחיל\n`;
prompt += `2. בדוק את הקבצים הרלוונטיים שמוזכרים בתיאור המשימה\n`;
prompt += `3. כתוב את הקוד לפי ה-Acceptance Criteria\n`;
prompt += `4. הרץ בדיקות ווודא שהכל עובד\n`;

return [{ json: { taskId: $('Webhook Trigger').item.json.body.taskId, prompt, task, nexusContext: nexus, sourceCount: webSources.length, docCount: docs.length } }];
